<script setup lang="ts">
import { computed, ref, watch } from "vue";
import { diffLines } from "diff";
import { message } from "@tauri-apps/plugin-dialog";
import MarkdownEditor from "./components/MarkdownEditor.vue";
import MarkdownPreview from "./components/MarkdownPreview.vue";
import { useDocumentStore } from "./stores/document";
import { categoryLabels, repairRules, rulesForCategory } from "./repair/registry";
import { editsForPlan } from "./repair/planner";
import { promoteSection, demoteSection, shiftSectionNumber, deleteSection, autoNumberSections, renumberSections, moveSectionBefore } from "./core/sections";
import { chooseMarkdownFile, chooseSavePath, fileNameFromPath, readMarkdown, writeMarkdown } from "./services/nativeFiles";
import type { RepairCategory, RepairPlan, RepairTarget } from "./types";

const store = useDocumentStore(); const sideTab = ref<"sections" | "issues">("sections"); const centerTab = ref<"source" | "repair" | "diff">("source"); const status = ref("准备就绪"); const sourceEditor = ref<{ scrollToPosition: (p: number) => void; setScrollRatio: (r: number) => void }>(); const repairEditor = ref<{ setScrollRatio: (r: number) => void }>(); const preview = ref<{ setScrollRatio: (r: number) => void }>(); const diffRoot = ref<HTMLElement>(); const menu = ref<"file" | "repair" | "history" | null>(null); const settingsOpen = ref(false); const context = ref<{ id: string; x: number; y: number }>(); const dragging = ref<string>(); const lastPreview = ref<"source" | "repair">("source");
const currentPlan = ref<RepairPlan>(store.buildRepairPlan("document", { kind: "automatic" })); const selectedPlanIds = ref<string[]>(currentPlan.value.candidates.map(item => item.id)); const pendingManual = ref<{ selection: RepairPlan; full: RepairPlan }>();
const repairText = computed(() => store.preview(editsForPlan(currentPlan.value, selectedPlanIds.value))); const diffs = computed(() => diffLines(store.text, repairText.value)); const previewText = computed(() => lastPreview.value === "repair" ? repairText.value : store.text); const issues = computed(() => currentPlan.value.candidates); const categories = Object.keys(categoryLabels) as RepairCategory[];
interface Profile { id: string; name: string; enabledRuleIds: string[]; minimumConfidence: number; builtIn?: boolean }
const profileKey = "mdtool.repair-profiles.v1"; const profiles = ref<Profile[]>(loadProfiles()); const activeProfileId = ref(profiles.value[0].id); const profileName = ref("新规则方案");
function loadProfiles(): Profile[] { try { const raw = JSON.parse(localStorage.getItem(profileKey) || "null") as Profile[] | null; if (raw?.length) return raw; } catch { /* fallback */ } return [{ id: "default", name: "默认安全方案", enabledRuleIds: [...store.repairSettings.enabledRuleIds], minimumConfidence: store.repairSettings.minimumConfidence, builtIn: true }]; }
function persistProfiles() { try { localStorage.setItem(profileKey, JSON.stringify(profiles.value)); } catch { /* non-fatal */ } }
function activateProfile(id: string) { const profile = profiles.value.find(item => item.id === id); if (!profile) return; activeProfileId.value = id; store.updateRepairSettings({ enabledRuleIds: profile.enabledRuleIds, minimumConfidence: profile.minimumConfidence }); refreshAutomatic(); }
function saveProfile() { const name = profileName.value.trim(); if (!name) return; const current = profiles.value.find(item => item.id === activeProfileId.value); if (current && !current.builtIn) { current.name = name; current.enabledRuleIds = [...store.repairSettings.enabledRuleIds]; current.minimumConfidence = store.repairSettings.minimumConfidence; } else { const profile = { id: `profile-${Date.now()}`, name, enabledRuleIds: [...store.repairSettings.enabledRuleIds], minimumConfidence: store.repairSettings.minimumConfidence }; profiles.value.push(profile); activeProfileId.value = profile.id; } persistProfiles(); }
function deleteProfile() { const profile = profiles.value.find(item => item.id === activeProfileId.value); if (!profile || profile.builtIn) return; profiles.value = profiles.value.filter(item => item.id !== profile.id); activateProfile("default"); persistProfiles(); }
function toggleRule(id: string, checked: boolean) { const ids = new Set(store.repairSettings.enabledRuleIds); checked ? ids.add(id) : ids.delete(id); store.updateRepairSettings({ ...store.repairSettings, enabledRuleIds: [...ids] }); const profile = profiles.value.find(item => item.id === activeProfileId.value); if (profile && !profile.builtIn) { profile.enabledRuleIds = [...ids]; persistProfiles(); } refreshAutomatic(); }
function refreshAutomatic() { currentPlan.value = store.buildRepairPlan("document", { kind: "automatic" }); selectedPlanIds.value = currentPlan.value.candidates.map(item => item.id); }
watch(() => store.text, () => { refreshAutomatic(); if (centerTab.value === "source") lastPreview.value = "source"; });
function selectCenter(tab: "source" | "repair" | "diff") { centerTab.value = tab; if (tab !== "diff") lastPreview.value = tab; }
function syncScroll(ratio: number) { preview.value?.setScrollRatio(ratio); }
function onDiffScroll() { const el = diffRoot.value; if (!el) return; const max = Math.max(1, el.scrollHeight - el.clientHeight); syncScroll(el.scrollTop / max); }
function jump(offset: number) { selectCenter("source"); requestAnimationFrame(() => sourceEditor.value?.scrollToPosition(offset)); }
function run(label: string, edits: ReturnType<typeof promoteSection>) { try { store.run(label, edits); status.value = `${label}已应用`; } catch (error) { status.value = error instanceof Error ? error.message : "操作失败"; } }
function startManual(target: RepairTarget) { const hasSelection = store.selection.from !== store.selection.to; const full = store.buildRepairPlan("document", target); if (!hasSelection) { currentPlan.value = full; selectedPlanIds.value = full.candidates.map(item => item.id); selectCenter("repair"); return; } pendingManual.value = { selection: store.buildRepairPlan("selection", target), full }; }
function resolveManual(mode: "selection" | "all") { const plan = mode === "selection" ? pendingManual.value!.selection : pendingManual.value!.full; pendingManual.value = undefined; currentPlan.value = plan; selectedPlanIds.value = plan.candidates.map(item => item.id); selectCenter("repair"); }
function applyPlan() { try { store.applyRepairPlan(currentPlan.value, selectedPlanIds.value, "应用修复预览"); status.value = "已应用修复，可一次撤销"; refreshAutomatic(); selectCenter("source"); } catch (error) { status.value = error instanceof Error ? error.message : "修复失败"; } }
function oneClick() { refreshAutomatic(); selectCenter("repair"); }
function undo() { store.undo(); status.value = "已撤销"; } function redo() { store.redo(); status.value = "已重做"; }
function undoTo(at: number) { store.undoTo(at); status.value = "已撤销到指定历史"; menu.value = null; }
async function saveDocument(copy = false): Promise<boolean> { try { const path = copy || !store.filePath ? await chooseSavePath(store.filePath ?? store.fileName) : store.filePath; if (!path) return false; await writeMarkdown(path, store.text); if (!copy) store.markSaved(path, fileNameFromPath(path)); status.value = copy ? "已另存为" : "已保存"; return true; } catch (error) { status.value = error instanceof Error ? error.message : "保存失败"; return false; } }
async function resolveUnsaved(): Promise<boolean> { if (!store.dirty) return true; const result = String(await message("当前文档有未保存修改。", { title: "保存修改？", kind: "warning", buttons: { yes: "保存", no: "放弃", cancel: "取消" } })).toLowerCase(); return result === "yes" ? saveDocument() : result === "no"; }
async function newDocument() { if (await resolveUnsaved()) store.loadDocument(""); } async function openDocument() { if (!await resolveUnsaved()) return; const path = await chooseMarkdownFile(); if (!path) return; store.loadDocument(await readMarkdown(path), { filePath: path, fileName: fileNameFromPath(path) }); }
function sectionAction(action: string) { const id = context.value?.id; if (!id) return; if (action === "promote") run("提升章节", promoteSection(store.text, id)); if (action === "demote") run("降级章节", demoteSection(store.text, id)); if (action === "plus") run("编号加一", shiftSectionNumber(store.text, id, 1)); if (action === "minus") run("编号减一", shiftSectionNumber(store.text, id, -1)); if (action === "delete") run("删除章节", deleteSection(store.text, id)); context.value = undefined; }
function dropSection(targetId: string) { if (!dragging.value || dragging.value === targetId) return; run("拖拽调整章节并重编号", moveSectionBefore(store.text, dragging.value, targetId)); dragging.value = undefined; }
</script>
<template>
  <main class="app" @click="menu = null; context = undefined">
    <header class="menubar" @click.stop><div class="menus"><button @click="menu = menu === 'file' ? null : 'file'">文件</button><div v-if="menu === 'file'" class="dropdown"><button @click="newDocument">新建</button><button @click="openDocument">打开</button><button @click="saveDocument()">保存</button><button @click="saveDocument(true)">另存为</button></div><button @click="menu = menu === 'repair' ? null : 'repair'">修复规则</button><div v-if="menu === 'repair'" class="dropdown repair-menu"><div v-for="category in categories" :key="category"><strong>{{ categoryLabels[category] }}</strong><button @click="startManual({ kind: 'category', id: category })">修复此类已启用规则</button><button v-for="rule in rulesForCategory(category)" :key="rule.id" @click="startManual({ kind: 'rule', id: rule.id })">{{ rule.label }}</button></div></div><button @click="settingsOpen = true">规则设定</button><button class="accent" @click="oneClick">一键修复</button><button @click="undo" :disabled="!store.history.canUndo">撤销</button><button @click="menu = menu === 'history' ? null : 'history'">⌄</button><div v-if="menu === 'history'" class="dropdown history-menu"><button v-for="entry in store.history.list()" :key="entry.at" @click="undoTo(entry.at)">{{ entry.label }}</button></div><button @click="redo" :disabled="!store.history.canRedo">重做</button></div><span>{{ status }}</span></header>
    <section class="workspace"><aside class="left"><nav><button :class="{ active: sideTab === 'sections' }" @click="sideTab = 'sections'">章节</button><button :class="{ active: sideTab === 'issues' }" @click="sideTab = 'issues'">修复项 <b>{{ issues.length }}</b></button></nav><div v-if="sideTab === 'sections'" class="side-list"><button v-for="section in store.sections" :key="section.id" draggable="true" :style="{ paddingLeft: `${(section.level - 1) * 16 + 8}px` }" @dragstart="dragging = section.id" @dragover.prevent @drop.prevent="dropSection(section.id)" @click="jump(section.headingFrom)" @contextmenu.prevent.stop="context = { id: section.id, x: $event.clientX, y: $event.clientY }">{{ '#'.repeat(section.level) }} {{ section.numberParts?.join('.') }} {{ section.title }}</button></div><div v-else class="side-list"><button v-for="item in issues" :key="item.id" @click="jump(item.from)"><small>{{ categoryLabels[item.category] }}</small>{{ item.label }}</button><p v-if="!issues.length">当前方案未发现可修复项</p></div></aside>
      <section class="center"><nav><button :class="{ active: centerTab === 'source' }" @click="selectCenter('source')">源码</button><button :class="{ active: centerTab === 'repair' }" @click="selectCenter('repair')">修复预览</button><button :class="{ active: centerTab === 'diff' }" @click="selectCenter('diff')">差异</button><button v-if="centerTab === 'repair'" class="apply" :disabled="!selectedPlanIds.length" @click="applyPlan">应用预览（{{ selectedPlanIds.length }}）</button></nav><MarkdownEditor v-if="centerTab === 'source'" ref="sourceEditor" :model-value="store.text" @update:model-value="store.replace" @paste-document="store.loadPastedDocument" @selection-change="(from, to) => store.setSelection({ from, to })" @scroll="syncScroll" @undo="undo" @redo="redo" /><MarkdownEditor v-else-if="centerTab === 'repair'" ref="repairEditor" :model-value="repairText" readonly @scroll="syncScroll" /><article v-else ref="diffRoot" class="diff" @scroll="onDiffScroll"><pre v-for="(part, index) in diffs" :key="index" :class="{ added: part.added, removed: part.removed }">{{ part.value }}</pre></article></section>
      <aside class="right"><p class="title">预览</p><MarkdownPreview ref="preview" :model-value="previewText" /></aside></section>
    <div v-if="context" class="context" :style="{ left: `${context.x}px`, top: `${context.y}px` }" @click.stop><button @click="sectionAction('promote')">提升章节</button><button @click="sectionAction('demote')">降级章节</button><button @click="sectionAction('plus')">编号 +1</button><button @click="sectionAction('minus')">编号 −1</button><button @click="run('自动编号', autoNumberSections(store.text)); context = undefined">自动编号</button><button @click="run('连续编号', renumberSections(store.text)); context = undefined">连续编号</button><button @click="sectionAction('delete')">删除章节</button></div>
    <div v-if="pendingManual" class="modal"><section><h3>检测到选区</h3><p>是否只修复选区，还是将相同规则应用到剩余区域？</p><button @click="pendingManual = undefined">取消</button><button @click="resolveManual('selection')">仅修复选区</button><button class="accent" @click="resolveManual('all')">选区和余区一起修复</button></section></div>
    <div v-if="settingsOpen" class="modal"><section class="settings"><button class="close" @click="settingsOpen = false">×</button><h3>规则方案设定</h3><div class="profile-row"><select :value="activeProfileId" @change="activateProfile(($event.target as HTMLSelectElement).value)"><option v-for="profile in profiles" :key="profile.id" :value="profile.id">{{ profile.name }}</option></select><input v-model="profileName" placeholder="方案名称"><button @click="saveProfile">保存为方案</button><button @click="deleteProfile">删除</button></div><label v-for="rule in repairRules" :key="rule.id" class="rule-setting"><input type="checkbox" :checked="store.repairSettings.enabledRuleIds.includes(rule.id)" @change="toggleRule(rule.id, ($event.target as HTMLInputElement).checked)"><span><strong>{{ categoryLabels[rule.category] }} · {{ rule.label }}</strong><small>示例：{{ rule.id === 'formula-trim' ? '$  x + y  $ → $x + y$' : rule.id === 'invisible-character' ? '含零宽字符 → 普通空格' : '检测到的问题文本 → 规范化文本' }}</small></span></label><label>最低置信度 <input type="number" min="0" max="1" step="0.1" :value="store.repairSettings.minimumConfidence" @change="store.updateRepairSettings({ ...store.repairSettings, minimumConfidence: Number(($event.target as HTMLInputElement).value) }); refreshAutomatic()"></label></section></div>
  </main>
</template>
<style>
:root { font-family: "Microsoft YaHei UI", sans-serif; color:#d5dfda; background:#071012; } *{box-sizing:border-box} body{margin:0;min-width:960px}.app{height:100vh;display:grid;grid-template-rows:42px 1fr;background:#071012}.menubar{display:flex;justify-content:space-between;align-items:center;padding:0 12px;background:#0a1517;border-bottom:1px solid #294347;font-size:12px;color:#78908c}.menus{display:flex;align-items:center;gap:4px;position:relative}.menubar button,.left button,.center nav button,.context button,.modal button{border:0;background:transparent;color:inherit;padding:7px 9px;cursor:pointer;font:inherit}.menubar .accent,.apply,.modal .accent{background:#e6a845!important;color:#17201d!important;border-radius:3px;font-weight:700}.dropdown{position:absolute;top:34px;left:0;z-index:20;display:grid;min-width:130px;padding:6px;background:#102024;border:1px solid #315052;box-shadow:0 10px 28px #0008}.dropdown button{text-align:left}.repair-menu{left:55px;grid-template-columns:repeat(2,minmax(160px,1fr));max-width:430px}.repair-menu div{display:grid;padding:6px}.history-menu{left:420px}.workspace{min-height:0;display:grid;grid-template-columns:250px minmax(420px,1fr) minmax(320px,.75fr)}.left,.right{min-height:0;background:#0c1719}.left{border-right:1px solid #294347}.right{border-left:1px solid #294347}.left nav,.center nav{display:flex;align-items:center;height:42px;padding:0 10px;border-bottom:1px solid #294347}.left nav button,.center nav button{color:#78908c}.left nav .active,.center nav .active{color:#f1b75b;border-bottom:2px solid #f1b75b}.left b{color:#f1b75b}.side-list{overflow:auto;height:calc(100% - 42px);padding:8px}.side-list button{display:block;width:100%;text-align:left;border:0;background:transparent;color:#c6d2cf;padding:8px;border-radius:3px}.side-list button:hover{background:#153032}.side-list small{display:block;color:#78908c}.side-list p{color:#78908c;text-align:center}.center{min-width:0;min-height:0;display:grid;grid-template-rows:42px 1fr}.center nav .apply{margin-left:auto}.right{display:grid;grid-template-rows:42px 1fr}.title{margin:0;padding:13px 18px;border-bottom:1px solid #294347;color:#f1b75b;font-size:12px}.diff{overflow:auto;padding:20px;background:#10191c}.diff pre{white-space:pre-wrap;margin:0;padding:4px 8px;font:13px/1.55 "Cascadia Code",monospace}.diff .added{background:#18382f;color:#aedac2}.diff .removed{background:#3b2425;color:#e5b8b2;text-decoration:line-through}.context{position:fixed;z-index:30;display:grid;background:#102024;border:1px solid #315052;box-shadow:0 10px 28px #0008}.context button{text-align:left}.modal{position:fixed;inset:0;z-index:50;display:grid;place-items:center;background:#0009}.modal section{width:min(620px,90vw);max-height:80vh;overflow:auto;background:#102024;border:1px solid #466b65;padding:22px;display:grid;gap:10px}.settings{position:relative}.close{position:absolute;right:8px;top:8px;font-size:20px}.profile-row{display:flex;gap:6px}.profile-row select,.profile-row input,.settings input[type=number]{background:#0a1517;color:#d5dfda;border:1px solid #315052;padding:6px}.rule-setting{display:flex;gap:9px;padding:8px;border-left:2px solid #315052}.rule-setting small{display:block;color:#78908c;margin-top:4px}button:disabled{opacity:.4;cursor:not-allowed}
</style>
